// // This synchronous flip-flop captures the input signal 'data' on the falling edge of the clock signal 'clk'. If the 'reset' signal is deasserted, the output 'q' is set to a LOW state (0).
module top_module(
data  ,
clk    ,
reset ,
q     
);input data, clk, reset ; 
output q;
(*ASYNC_REG = "TRUE" *) reg q;
always @ ( posedge clk or posedge reset) begin
  if (reset) begin
    q <= 1'b1;
  end  else begin
    q <= data;
  end
end
endmodule
